(window.webpackJsonp=window.webpackJsonp||[]).push([[969],{912:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">dungeon</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> calculateMinimumHP = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">dungeon</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> row=dungeon.length,\\n        col=dungeon[<span class=\\"hljs-number\\">0</span>].length\\n    <span class=\\"hljs-comment\\">// let dp=Array(row).fill(0).map(Array(col).fill(0))</span>\\n    <span class=\\"hljs-comment\\">// dp[0][0]=[Math.min(0-dungeon[0][0],0)+1,1]</span>\\n    <span class=\\"hljs-comment\\">// for(let i=0;i&lt;row;i++){</span>\\n    <span class=\\"hljs-comment\\">//     for(let j=0;j&lt;col;j++){</span>\\n    <span class=\\"hljs-comment\\">//         let curNeed=Math.min(0,0-dungeon[i][j])+1</span>\\n    <span class=\\"hljs-comment\\">//         let leftNeed=Math.max(0,curNeed-dp[i][j-1][1])</span>\\n    <span class=\\"hljs-comment\\">//         dp[i][j]=[]</span>\\n    <span class=\\"hljs-comment\\">//     }</span>\\n    <span class=\\"hljs-comment\\">// }</span>\\n    <span class=\\"hljs-keyword\\">let</span> moves=[[<span class=\\"hljs-number\\">1</span>,<span class=\\"hljs-number\\">0</span>],[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">1</span>]]\\n    <span class=\\"hljs-keyword\\">let</span> firstNeed=<span class=\\"hljs-built_in\\">Math</span>.max(<span class=\\"hljs-number\\">0</span>-dungeon[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">0</span>],<span class=\\"hljs-number\\">0</span>)+<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">let</span> arr=[[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">0</span>,firstNeed,firstNeed+dungeon[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">0</span>]]]\\n    <span class=\\"hljs-keyword\\">let</span> minNeed=<span class=\\"hljs-literal\\">Infinity</span>\\n    <span class=\\"hljs-keyword\\">while</span>(arr.length&gt;<span class=\\"hljs-number\\">0</span>){\\n        <span class=\\"hljs-comment\\">// console.log(arr)</span>\\n        <span class=\\"hljs-keyword\\">let</span> len=arr.length\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n            <span class=\\"hljs-keyword\\">let</span> [x,y,preNeed,preRest]=arr.shift()\\n            <span class=\\"hljs-keyword\\">if</span>(x===row<span class=\\"hljs-number\\">-1</span> &amp;&amp; y===col<span class=\\"hljs-number\\">-1</span>)minNeed=<span class=\\"hljs-built_in\\">Math</span>.min(minNeed,preNeed)\\n            <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [dx,dy] <span class=\\"hljs-keyword\\">of</span> moves){\\n                <span class=\\"hljs-keyword\\">let</span> newx=x+dx,newy=y+dy\\n                <span class=\\"hljs-keyword\\">if</span>(newx&lt;<span class=\\"hljs-number\\">0</span> || newy&lt;<span class=\\"hljs-number\\">0</span> || newx&gt;=row || newy&gt;=col)<span class=\\"hljs-keyword\\">continue</span>\\n                <span class=\\"hljs-keyword\\">let</span> cur=dungeon[newx][newy]\\n                <span class=\\"hljs-comment\\">// let [preNeed,preRest]=dp[x][y]</span>\\n                <span class=\\"hljs-keyword\\">let</span> curNeed,curRest\\n                <span class=\\"hljs-keyword\\">if</span>(cur&lt;<span class=\\"hljs-number\\">0</span>){\\n                    curNeed=preNeed+<span class=\\"hljs-built_in\\">Math</span>.max(<span class=\\"hljs-number\\">0</span>,-cur+<span class=\\"hljs-number\\">1</span>-preRest)\\n                    curRest=preRest+curNeed+cur-preNeed\\n                }<span class=\\"hljs-keyword\\">else</span>{\\n                    curNeed=<span class=\\"hljs-number\\">0</span>+preNeed\\n                    curRest=preRest+curNeed+cur-preNeed\\n                }\\n                arr.push([newx,newy,curNeed,curRest])\\n            }\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> minNeed\\n};\\n</code></pre>\\n","<pre class=\\"hljs\\"><code><span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">calculateMinimumHP</span><span class=\\"hljs-params\\">(self, dungeon)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type dungeon: List[List[int]]\\n        :rtype: int\\n        \\"\\"\\"</span>\\n        m=len(dungeon)\\n        n=len(dungeon[<span class=\\"hljs-number\\">0</span>])\\n        dp=[[float(<span class=\\"hljs-string\\">\'inf\'</span>)]*(n+<span class=\\"hljs-number\\">1</span>) <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(m+<span class=\\"hljs-number\\">1</span>)]\\n        dp[m][n<span class=\\"hljs-number\\">-1</span>]=<span class=\\"hljs-number\\">1</span>\\n        dp[m<span class=\\"hljs-number\\">-1</span>][n]=<span class=\\"hljs-number\\">1</span>\\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(m<span class=\\"hljs-number\\">-1</span>,<span class=\\"hljs-number\\">-1</span>,<span class=\\"hljs-number\\">-1</span>):\\n          <span class=\\"hljs-keyword\\">for</span> j <span class=\\"hljs-keyword\\">in</span> range(n<span class=\\"hljs-number\\">-1</span>,<span class=\\"hljs-number\\">-1</span>,<span class=\\"hljs-number\\">-1</span>):\\n            dp[i][j]=min(dp[i+<span class=\\"hljs-number\\">1</span>][j]-dungeon[i][j],dp[i][j+<span class=\\"hljs-number\\">1</span>]-dungeon[i][j])\\n            <span class=\\"hljs-keyword\\">if</span> dp[i][j]&lt;<span class=\\"hljs-number\\">1</span>:\\n              dp[i][j]=<span class=\\"hljs-number\\">1</span>\\n              \\n        <span class=\\"hljs-keyword\\">return</span> dp[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">0</span>]\\n</code></pre>\\n"],"titleSlug":"dungeon-game","hasThinking":false,"content":"<style>\\r\\ntable.dungeon, .dungeon th, .dungeon td {\\r\\n  border:3px solid black;\\r\\n}\\r\\n\\r\\n .dungeon th, .dungeon td {\\r\\n    text-align: center;\\r\\n    height: 70px;\\r\\n    width: 70px;\\r\\n}\\r\\n</style>\\r\\n\\r\\n<p>\u4e00\u4e9b\u6076\u9b54\u6293\u4f4f\u4e86\u516c\u4e3b\uff08<strong>P</strong>\uff09\u5e76\u5c06\u5979\u5173\u5728\u4e86\u5730\u4e0b\u57ce\u7684\u53f3\u4e0b\u89d2\u3002\u5730\u4e0b\u57ce\u662f\u7531&nbsp;M x N \u4e2a\u623f\u95f4\u7ec4\u6210\u7684\u4e8c\u7ef4\u7f51\u683c\u3002\u6211\u4eec\u82f1\u52c7\u7684\u9a91\u58eb\uff08<strong>K</strong>\uff09\u6700\u521d\u88ab\u5b89\u7f6e\u5728\u5de6\u4e0a\u89d2\u7684\u623f\u95f4\u91cc\uff0c\u4ed6\u5fc5\u987b\u7a7f\u8fc7\u5730\u4e0b\u57ce\u5e76\u901a\u8fc7\u5bf9\u6297\u6076\u9b54\u6765\u62ef\u6551\u516c\u4e3b\u3002</p>\\r\\n\\r\\n<p>\u9a91\u58eb\u7684\u521d\u59cb\u5065\u5eb7\u70b9\u6570\u4e3a\u4e00\u4e2a\u6b63\u6574\u6570\u3002\u5982\u679c\u4ed6\u7684\u5065\u5eb7\u70b9\u6570\u5728\u67d0\u4e00\u65f6\u523b\u964d\u81f3 0 \u6216\u4ee5\u4e0b\uff0c\u4ed6\u4f1a\u7acb\u5373\u6b7b\u4ea1\u3002</p>\\r\\n\\r\\n<p>\u6709\u4e9b\u623f\u95f4\u7531\u6076\u9b54\u5b88\u536b\uff0c\u56e0\u6b64\u9a91\u58eb\u5728\u8fdb\u5165\u8fd9\u4e9b\u623f\u95f4\u65f6\u4f1a\u5931\u53bb\u5065\u5eb7\u70b9\u6570\uff08\u82e5\u623f\u95f4\u91cc\u7684\u503c\u4e3a<em>\u8d1f\u6574\u6570</em>\uff0c\u5219\u8868\u793a\u9a91\u58eb\u5c06\u635f\u5931\u5065\u5eb7\u70b9\u6570\uff09\uff1b\u5176\u4ed6\u623f\u95f4\u8981\u4e48\u662f\u7a7a\u7684\uff08\u623f\u95f4\u91cc\u7684\u503c\u4e3a <em>0</em>\uff09\uff0c\u8981\u4e48\u5305\u542b\u589e\u52a0\u9a91\u58eb\u5065\u5eb7\u70b9\u6570\u7684\u9b54\u6cd5\u7403\uff08\u82e5\u623f\u95f4\u91cc\u7684\u503c\u4e3a<em>\u6b63\u6574\u6570</em>\uff0c\u5219\u8868\u793a\u9a91\u58eb\u5c06\u589e\u52a0\u5065\u5eb7\u70b9\u6570\uff09\u3002</p>\\r\\n\\r\\n<p>\u4e3a\u4e86\u5c3d\u5feb\u5230\u8fbe\u516c\u4e3b\uff0c\u9a91\u58eb\u51b3\u5b9a\u6bcf\u6b21\u53ea\u5411\u53f3\u6216\u5411\u4e0b\u79fb\u52a8\u4e00\u6b65\u3002</p>\\r\\n\\r\\n<p>&nbsp;</p>\\r\\n\\r\\n<p><strong>\u7f16\u5199\u4e00\u4e2a\u51fd\u6570\u6765\u8ba1\u7b97\u786e\u4fdd\u9a91\u58eb\u80fd\u591f\u62ef\u6551\u5230\u516c\u4e3b\u6240\u9700\u7684\u6700\u4f4e\u521d\u59cb\u5065\u5eb7\u70b9\u6570\u3002</strong></p>\\r\\n\\r\\n<p>\u4f8b\u5982\uff0c\u8003\u8651\u5230\u5982\u4e0b\u5e03\u5c40\u7684\u5730\u4e0b\u57ce\uff0c\u5982\u679c\u9a91\u58eb\u9075\u5faa\u6700\u4f73\u8def\u5f84 <code>\u53f3 -&gt; \u53f3 -&gt; \u4e0b -&gt; \u4e0b</code>\uff0c\u5219\u9a91\u58eb\u7684\u521d\u59cb\u5065\u5eb7\u70b9\u6570\u81f3\u5c11\u4e3a <strong>7</strong>\u3002</p>\\r\\n\\r\\n<table class=\\"dungeon\\">\\r\\n<tr> \\r\\n<td>-2 (K)</td> \\r\\n<td>-3</td> \\r\\n<td>3</td> \\r\\n</tr> \\r\\n<tr> \\r\\n<td>-5</td> \\r\\n<td>-10</td> \\r\\n<td>1</td> \\r\\n</tr> \\r\\n<tr> \\r\\n<td>10</td> \\r\\n<td>30</td> \\r\\n<td>-5 (P)</td> \\r\\n</tr> \\r\\n</table>\\r\\n\x3c!---2K   -3  3\\r\\n-5   -10   1\\r\\n10 30   5P--\x3e\\r\\n\\r\\n<p>&nbsp;</p>\\r\\n\\r\\n<p><strong>\u8bf4\u660e:</strong></p>\\r\\n\\r\\n<ul>\\r\\n\\t<li>\\r\\n\\t<p>\u9a91\u58eb\u7684\u5065\u5eb7\u70b9\u6570\u6ca1\u6709\u4e0a\u9650\u3002</p>\\r\\n\\t</li>\\r\\n\\t<li>\u4efb\u4f55\u623f\u95f4\u90fd\u53ef\u80fd\u5bf9\u9a91\u58eb\u7684\u5065\u5eb7\u70b9\u6570\u9020\u6210\u5a01\u80c1\uff0c\u4e5f\u53ef\u80fd\u589e\u52a0\u9a91\u58eb\u7684\u5065\u5eb7\u70b9\u6570\uff0c\u5305\u62ec\u9a91\u58eb\u8fdb\u5165\u7684\u5de6\u4e0a\u89d2\u623f\u95f4\u4ee5\u53ca\u516c\u4e3b\u88ab\u76d1\u7981\u7684\u53f3\u4e0b\u89d2\u623f\u95f4\u3002</li>\\r\\n</ul>","title":"174. \u5730\u4e0b\u57ce\u6e38\u620f","relatedTags":["\u4e8c\u5206\u67e5\u627e","\u52a8\u6001\u89c4\u5212"],"difficult":"Hard","lang":["javascript","python"],"uniqueID":"174"}')}}]);